package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithFirstRecordAsHeader() {
        CSVFormat baseFormat = CSVFormat.DEFAULT;
        CSVFormat resultFormat = baseFormat.withFirstRecordAsHeader();

        // It should be a new instance, not the same as baseFormat
        assertNotSame(baseFormat, resultFormat);

        // The result should have skipHeaderRecord = true
        assertTrue(resultFormat.getSkipHeaderRecord());

        // The result should have a non-null header set (empty header)
        assertNotNull(resultFormat.getHeader());

        // The header array should be empty (withHeader() sets empty header)
        assertEquals(0, resultFormat.getHeader().length);

        // The original format should remain unchanged
        assertFalse(baseFormat.getSkipHeaderRecord());
        // baseFormat.getHeader() returns null by default
        assertNull(baseFormat.getHeader());
    }
}
